class Solution:
    def findRedundantConnection(self, edges):
        n = len(edges)
        nodes = set()
        for a, b in edges:
            nodes.add(a); nodes.add(b)
        for k in range(n - 1, -1, -1):
            adj = {}
            for j in range(n):
                if j == k:
                    continue
                a, b = edges[j]
                adj.setdefault(a, []).append(b)
                adj.setdefault(b, []).append(a)
            seen = set()
            stack = [next(iter(nodes))]
            while stack:
                x = stack.pop()
                if x in seen:
                    continue
                seen.add(x)
                for y in adj.get(x, []):
                    if y not in seen:
                        stack.append(y)
            if len(seen) == len(nodes):
                return edges[k]
        return edges[-1]

